import{_ as e,c as i,o as a,ag as s}from"./chunks/framework.CSeR4K32.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/guide/podman/podman_precheck.md","filePath":"en/guide/podman/podman_precheck.md","lastUpdated":1772421927000}'),d={name:"en/guide/podman/podman_precheck.md"};function n(r,t,o,l,p,c){return a(),i("div",null,t[0]||(t[0]=[s('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The following is an introduction to the non-customized sections. Please ensure that you don&#39;t confuse them with the customized parts.</p><p>If your host does not have an IPv6 subnet and you want to assign IPv6 addresses to containers, the host itself needs a public IPv6 address. The installation script will automatically detect and configure this.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The Podman solution <strong>does not support KVM/QEMU virtual machines</strong>. It only supports Linux containers (LXC) and is suitable for environments without KVM hardware virtualization support.</p></div><p>Feel free to give the project a <code>Star</code> for free support! --&gt; <a href="https://github.com/oneclickvirt/podman" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/podman</a></p><h2 id="project-features" tabindex="-1">Project Features <a class="header-anchor" href="#project-features" aria-label="Permalink to &quot;Project Features&quot;">​</a></h2><p>Bulk or individual NAT server provisioning based on Podman (daemonless architecture) runtime</p><ul><li>Uses each distribution&#39;s official packages to install Podman (no daemon, daemonless architecture)</li><li>Uses self-compiled base images (stored in GitHub Releases), with offline loading prioritized and fallback to ghcr.io images</li><li>Each container comes with 1 external SSH port, 25 consistent internal/external ports, with optional independent IPv6 address binding</li><li>Supports lxcfs mounting (if lxcfs is installed on the host), providing real /proc view inside containers</li><li>Native rootless support (this solution runs as root to simplify network configuration)</li><li>Supports China CDN acceleration</li></ul><h2 id="supported-systems" tabindex="-1">Supported Systems <a class="header-anchor" href="#supported-systems" aria-label="Permalink to &quot;Supported Systems&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>amd64</th><th>arm64</th></tr></thead><tbody><tr><td>Ubuntu 22.04</td><td>✓</td><td>✓</td></tr><tr><td>Debian 12</td><td>✓</td><td>✓</td></tr><tr><td>Alpine latest</td><td>✓</td><td>✓</td></tr><tr><td>AlmaLinux 9</td><td>✓</td><td>✓</td></tr><tr><td>RockyLinux 9</td><td>✓</td><td>✓</td></tr><tr><td>OpenEuler 22.03</td><td>✓</td><td>✓</td></tr></tbody></table><h2 id="configuration-requirements" tabindex="-1">Configuration Requirements <a class="header-anchor" href="#configuration-requirements" aria-label="Permalink to &quot;Configuration Requirements&quot;">​</a></h2><ul><li>Host OS: Ubuntu, Debian, RockyLinux 9+, AlmaLinux 9+, CentOS 9+, Alpine, Arch</li><li>Architecture: x86_64 (amd64) or ARM64</li><li>Kernel must support overlay filesystem</li><li>Network must be able to connect to GitHub raw interface</li><li>At least 3GB free disk space</li><li><strong>No KVM hardware support required</strong></li></ul><h2 id="comparison-with-containerd-and-docker" tabindex="-1">Comparison with containerd and Docker <a class="header-anchor" href="#comparison-with-containerd-and-docker" aria-label="Permalink to &quot;Comparison with containerd and Docker&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>podman (this project)</th><th>containerd</th><th>docker</th></tr></thead><tbody><tr><td>Daemon</td><td>None (daemonless)</td><td>Lightweight containerd</td><td>Heavy Docker daemon</td></tr><tr><td>Runtime</td><td>crun/runc</td><td>runc</td><td>runc</td></tr><tr><td>CLI</td><td>podman</td><td>nerdctl</td><td>docker</td></tr><tr><td>Rootless support</td><td>Native</td><td>Requires config</td><td>Requires config</td></tr><tr><td>Image format</td><td>OCI</td><td>OCI</td><td>OCI</td></tr><tr><td>Network backend</td><td>netavark/CNI</td><td>CNI</td><td>Docker bridge</td></tr><tr><td>Container support</td><td>Linux containers (LXC)</td><td>Linux containers (LXC)</td><td>Linux containers + KVM VMs</td></tr><tr><td>Installation</td><td>System package manager</td><td>nerdctl-full bundle</td><td>Docker official script</td></tr></tbody></table><p>It is recommended to add some SWAP virtual memory before provisioning NAT servers to avoid host crash due to sudden memory spikes.</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/spiritLHLS/addswap/main/addswap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span></span></code></pre></div>',16)]))}const m=e(d,[["render",n]]);export{u as __pageData,m as default};
